function getCapitalLocations() {
  const caps = [];
  for (const [country, cities] of Object.entries(WORLD_CITIES)) {
    const cap = cities.find((c) => c.capital) || cities[0];
    caps.push({ ...cap, country });
  }
  return caps;
}

function getCityLocations() {
  const big = [];
  for (const [country, cities] of Object.entries(WORLD_CITIES)) {
    cities.filter((c) => c.isCity).forEach((c) => big.push({ ...c, country }));
  }
  return big;
}

function getCountryLocations(country) {
  return (WORLD_CITIES[country] || []).map((c) => ({ ...c, country }));
}

let cachedAllLocations = null;
let spatialHash = null;
const GRID_SIZE = 10;
function getAllLocations() {
  if (cachedAllLocations) return cachedAllLocations;
  const all = [];
  for (const [country, cities] of Object.entries(WORLD_CITIES)) {
    cities.forEach((c) => all.push({ ...c, country }));
  }
  cachedAllLocations = all;
  return all;
}
function getCitiesInBounds(bounds, zoom) {
  if (!spatialHash) {
    const all = getAllLocations();
    spatialHash = {};
    all.forEach((c) => {
      const gx = Math.floor(c.lng / GRID_SIZE);
      const gy = Math.floor(c.lat / GRID_SIZE);
      const key = `${gx},${gy}`;
      if (!spatialHash[key]) spatialHash[key] = [];
      spatialHash[key].push(c);
    });
  }
  const west = bounds.getWest(), east = bounds.getEast();
  const south = bounds.getSouth(), north = bounds.getNorth();
  const minX = Math.floor(west / GRID_SIZE), maxX = Math.floor(east / GRID_SIZE);
  const minY = Math.floor(south / GRID_SIZE), maxY = Math.floor(north / GRID_SIZE);
  const results = [];
  for (let x = minX; x <= maxX; x++) {
    for (let y = minY; y <= maxY; y++) {
      const cell = spatialHash[`${x},${y}`];
      if (cell) {
        for (const c of cell) {
          if (zoom < 4 && !c.isCapital) continue;
          if (zoom >= 4 && zoom < 7 && !c.isCapital && !c.isCity) continue;
          if (c.lat >= south && c.lat <= north && c.lng >= west && c.lng <= east) {
            results.push(c);
          }
        }
      }
    }
  }
  return results;
}

function findNearestCountry(lat, lng) {
  let best = null,
    bestDist = Infinity;
  for (const [country, cities] of Object.entries(WORLD_CITIES))
    for (const c of cities) {
      const d = Math.hypot(c.lat - lat, c.lng - lng);
      if (d < bestDist) {
        bestDist = d;
        best = country;
      }
    }
  return bestDist < 15 ? best : null;
}

export {
  WORLD_CITIES,
  getCapitalLocations,
  getCityLocations,
  getCountryLocations,
  getAllLocations,
  getCitiesInBounds,
  findNearestCountry,
};
